import{_ as a,o,c as l,ae as i}from"./chunks/framework.CC4GLy5w.js";const p=JSON.parse('{"title":"NanaSQLite セキュリティ／性能監査レポート（2026-03-09）","description":"","frontmatter":{},"headers":[],"relativePath":"security_audit.md","filePath":"security_audit.md"}'),t={name:"security_audit.md"};function c(d,e,r,s,n,h){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="nanasqlite-セキュリティ-性能監査レポート-2026-03-09" tabindex="-1">NanaSQLite セキュリティ／性能監査レポート（2026-03-09） <a class="header-anchor" href="#nanasqlite-セキュリティ-性能監査レポート-2026-03-09" aria-label="Permalink to &quot;NanaSQLite セキュリティ／性能監査レポート（2026-03-09）&quot;">​</a></h1><p>速度と後方互換性を優先しつつ、現行リポジトリを対象に脆弱性と高速化余地を確認した結果をまとめます。</p><h2 id="対象と方法" tabindex="-1">対象と方法 <a class="header-anchor" href="#対象と方法" aria-label="Permalink to &quot;対象と方法&quot;">​</a></h2><ul><li>対象コード: <ul><li><code>src/nanasqlite/core.py</code></li><li><code>src/nanasqlite/async_core.py</code></li><li><code>src/nanasqlite/sql_utils.py</code></li><li><code>tests/test_security.py</code></li><li><code>tests/test_benchmark.py</code></li><li><code>etc/poc/poc_sqli.py</code></li><li><code>etc/poc/poc_none.py</code></li></ul></li><li>実施した確認: <ul><li><code>pip install -e &quot;.[dev]&quot;</code></li><li><code>python -m tox -e lint</code></li><li><code>python -m tox -e type</code></li><li><code>python -m pytest tests/ -x</code></li><li>既存 PoC の再実行</li></ul></li></ul><h2 id="結論-要約" tabindex="-1">結論（要約） <a class="header-anchor" href="#結論-要約" aria-label="Permalink to &quot;結論（要約）&quot;">​</a></h2><ol><li><strong>現行 HEAD で再現できる新規クリティカル脆弱性は確認できませんでした。</strong></li><li>既知の重要問題である <strong><code>table</code> 引数経由の SQL injection</strong> は、<code>NanaSQLite._sanitize_identifier()</code> により現行版ではブロックされます（<code>src/nanasqlite/core.py:341-377</code>）。</li><li>既知の <strong><code>None</code> 値再読込時の整合性問題</strong> は <code>_NOT_FOUND</code> センチネルで修正済みです（<code>src/nanasqlite/core.py:74-75</code>, <code>src/nanasqlite/core.py:631-655</code>, <code>src/nanasqlite/core.py:865-882</code>）。</li><li>速度面では、<strong>既存 API を壊さずに改善できる余地</strong>がまだあります。特に <code>values()</code> / <code>items()</code> の全件ロード、<code>batch_get()</code> のキャッシュ確認、PRAGMA のまとめ実行は低リスクです（<code>src/nanasqlite/core.py:309-338</code>, <code>src/nanasqlite/core.py:825-929</code>）。</li></ol><h2 id="poc-で確認した事項" tabindex="-1">PoC で確認した事項 <a class="header-anchor" href="#poc-で確認した事項" aria-label="Permalink to &quot;PoC で確認した事項&quot;">​</a></h2><h3 id="_1-table-引数経由の-sql-injection-既知・修正済み" tabindex="-1">1. <code>table</code> 引数経由の SQL injection（既知・修正済み） <a class="header-anchor" href="#_1-table-引数経由の-sql-injection-既知・修正済み" aria-label="Permalink to &quot;1. `table` 引数経由の SQL injection（既知・修正済み）&quot;">​</a></h3><ul><li>PoC: <code>etc/poc/poc_sqli.py</code></li><li>関連コード: <ul><li><code>src/nanasqlite/core.py:143-151</code></li><li><code>src/nanasqlite/core.py:341-377</code></li><li><code>tests/test_security.py:95-102</code></li></ul></li></ul><h4 id="再現コマンド" tabindex="-1">再現コマンド <a class="header-anchor" href="#再現コマンド" aria-label="Permalink to &quot;再現コマンド&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> etc/poc/poc_sqli.py</span></span></code></pre></div><h4 id="現行版での確認結果" tabindex="-1">現行版での確認結果 <a class="header-anchor" href="#現行版での確認結果" aria-label="Permalink to &quot;現行版での確認結果&quot;">​</a></h4><ul><li>悪意あるテーブル名は <code>NanaSQLiteValidationError</code> で拒否される</li><li>既存の <code>users</code> テーブルは削除されない</li></ul><h4 id="評価" tabindex="-1">評価 <a class="header-anchor" href="#評価" aria-label="Permalink to &quot;評価&quot;">​</a></h4><ul><li><strong>深刻度（現行版）:</strong> 修正済み</li><li><strong>深刻度（未修正版の想定）:</strong> Critical</li><li><strong>後方互換性重視の推奨:</strong> 現状維持で問題ありません。将来も識別子を受ける新 API は必ず <code>_sanitize_identifier()</code> を通してください。</li></ul><h3 id="_2-none-値の再読込問題-既知・修正済み" tabindex="-1">2. <code>None</code> 値の再読込問題（既知・修正済み） <a class="header-anchor" href="#_2-none-値の再読込問題-既知・修正済み" aria-label="Permalink to &quot;2. `None` 値の再読込問題（既知・修正済み）&quot;">​</a></h3><ul><li>PoC: <code>etc/poc/poc_none.py</code></li><li>関連コード: <ul><li><code>src/nanasqlite/core.py:74-75</code></li><li><code>src/nanasqlite/core.py:631-655</code></li><li><code>src/nanasqlite/core.py:865-882</code></li></ul></li></ul><h4 id="再現コマンド-1" tabindex="-1">再現コマンド <a class="header-anchor" href="#再現コマンド-1" aria-label="Permalink to &quot;再現コマンド&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> etc/poc/poc_none.py</span></span></code></pre></div><h4 id="現行版での確認結果-1" tabindex="-1">現行版での確認結果 <a class="header-anchor" href="#現行版での確認結果-1" aria-label="Permalink to &quot;現行版での確認結果&quot;">​</a></h4><ul><li>DB 再オープン後も <code>None</code> が正しく取得できる</li><li><code>KeyError</code> は発生しない</li></ul><h4 id="評価-1" tabindex="-1">評価 <a class="header-anchor" href="#評価-1" aria-label="Permalink to &quot;評価&quot;">​</a></h4><ul><li><strong>深刻度（現行版）:</strong> 修正済み</li><li><strong>性質:</strong> データ整合性</li><li><strong>後方互換性重視の推奨:</strong> <code>_NOT_FOUND</code> センチネルの利用を継続し、呼び出し側では <code>is not _NOT_FOUND</code> 比較を維持してください。</li></ul><h2 id="現行版で見つかった「要監視」項目" tabindex="-1">現行版で見つかった「要監視」項目 <a class="header-anchor" href="#現行版で見つかった「要監視」項目" aria-label="Permalink to &quot;現行版で見つかった「要監視」項目&quot;">​</a></h2><p>ここからは <strong>現時点で即時の破壊的変更を入れるより、まず運用ガイドと opt-in 強化で対処すべき項目</strong> です。</p><h3 id="a-backup-restore-のパスは呼び出し元の信頼境界に依存" tabindex="-1">A. <code>backup()</code> / <code>restore()</code> のパスは呼び出し元の信頼境界に依存 <a class="header-anchor" href="#a-backup-restore-のパスは呼び出し元の信頼境界に依存" aria-label="Permalink to &quot;A. `backup()` / `restore()` のパスは呼び出し元の信頼境界に依存&quot;">​</a></h3><ul><li>関連コード: <code>src/nanasqlite/core.py:1222-1424</code></li><li>現状: <ul><li>自己コピー防止 (<code>os.path.samefile</code>) はある</li><li>インメモリ DB 文字列の拒否もある</li><li>ただし、<code>dest_path</code> / <code>src_path</code> 自体は「アプリが信頼したパス」であることを前提にしている</li></ul></li></ul><h4 id="リスク" tabindex="-1">リスク <a class="header-anchor" href="#リスク" aria-label="Permalink to &quot;リスク&quot;">​</a></h4><p>ライブラリ単体の致命的欠陥というより、<strong>アプリ側が未検証のユーザー入力をそのまま <code>backup()</code> / <code>restore()</code> に渡した場合の運用リスク</strong> です。</p><h4 id="推奨対応" tabindex="-1">推奨対応 <a class="header-anchor" href="#推奨対応" aria-label="Permalink to &quot;推奨対応&quot;">​</a></h4><ol><li><strong>最優先（非破壊）:</strong> ドキュメントで「ユーザー入力を直接渡さない」ことを明記する</li><li><strong>次点（opt-in）:</strong> <code>safe_base_dir</code> や <code>path_validator</code> のような追加引数で許可ディレクトリを制限する</li><li><strong>互換性優先:</strong> 既定動作は変えず、厳格化は opt-in に留める</li></ol><h3 id="b-asyncnanasqlite-は高負荷時にスレッドプール待ち行列が伸び得る" tabindex="-1">B. <code>AsyncNanaSQLite</code> は高負荷時にスレッドプール待ち行列が伸び得る <a class="header-anchor" href="#b-asyncnanasqlite-は高負荷時にスレッドプール待ち行列が伸び得る" aria-label="Permalink to &quot;B. `AsyncNanaSQLite` は高負荷時にスレッドプール待ち行列が伸び得る&quot;">​</a></h3><ul><li>関連コード: <code>src/nanasqlite/async_core.py:84-162</code></li><li>現状: <ul><li><code>ThreadPoolExecutor(max_workers=...)</code> でワーカー数は制限される</li><li>ただし投入数自体の制御はなく、バースト時の待ち行列長は呼び出し側依存</li></ul></li></ul><h4 id="リスク-1" tabindex="-1">リスク <a class="header-anchor" href="#リスク-1" aria-label="Permalink to &quot;リスク&quot;">​</a></h4><p>可用性（availability）寄りの問題です。高負荷 API サーバーでは、急激な <code>await asyncio.gather(...)</code> 連打で遅延が増える余地があります。</p><h4 id="推奨対応-1" tabindex="-1">推奨対応 <a class="header-anchor" href="#推奨対応-1" aria-label="Permalink to &quot;推奨対応&quot;">​</a></h4><ol><li><strong>最優先（非破壊）:</strong> ドキュメントで <code>max_workers</code> の調整指針を明記する</li><li><strong>次点（opt-in）:</strong> <code>max_pending_ops</code> または <code>asyncio.Semaphore</code> ベースの上限制御を追加する</li><li><strong>互換性優先:</strong> デフォルト値は現状維持にして、必要な利用者だけが有効化できるようにする</li></ol><h3 id="c-aead-暗号化は-aad-なしでも安全だが、将来の文脈結合は改善余地あり" tabindex="-1">C. AEAD 暗号化は AAD なしでも安全だが、将来の文脈結合は改善余地あり <a class="header-anchor" href="#c-aead-暗号化は-aad-なしでも安全だが、将来の文脈結合は改善余地あり" aria-label="Permalink to &quot;C. AEAD 暗号化は AAD なしでも安全だが、将来の文脈結合は改善余地あり&quot;">​</a></h3><ul><li>関連コード: <ul><li><code>src/nanasqlite/core.py:175-189</code></li><li><code>src/nanasqlite/core.py:618-623</code></li><li><code>src/nanasqlite/core.py:639-650</code></li></ul></li></ul><h4 id="現状" tabindex="-1">現状 <a class="header-anchor" href="#現状" aria-label="Permalink to &quot;現状&quot;">​</a></h4><p><code>AES-GCM</code> / <code>ChaCha20Poly1305</code> は正しく使われていますが、AAD（Additional Authenticated Data）は <code>None</code> です。</p><h4 id="評価-2" tabindex="-1">評価 <a class="header-anchor" href="#評価-2" aria-label="Permalink to &quot;評価&quot;">​</a></h4><p>これは <strong>即時脆弱性というより、将来のフォーマット拡張を安全にするための改善余地</strong> です。ここを今すぐ変えると既存 DB との互換性管理が必要になります。</p><h4 id="推奨対応-2" tabindex="-1">推奨対応 <a class="header-anchor" href="#推奨対応-2" aria-label="Permalink to &quot;推奨対応&quot;">​</a></h4><ol><li>互換性重視なら <strong>いまは変更しない</strong></li><li>将来やるなら、<strong>バージョン付き暗号化フォーマット</strong> を追加し、新フォーマットだけ AAD を使う</li><li>旧フォーマット読み込みは残して後方互換性を守る</li></ol><h2 id="高速化の余地" tabindex="-1">高速化の余地 <a class="header-anchor" href="#高速化の余地" aria-label="Permalink to &quot;高速化の余地&quot;">​</a></h2><h3 id="_1-values-items-が常に-load-all-を呼ぶ" tabindex="-1">1. <code>values()</code> / <code>items()</code> が常に <code>load_all()</code> を呼ぶ <a class="header-anchor" href="#_1-values-items-が常に-load-all-を呼ぶ" aria-label="Permalink to &quot;1. `values()` / `items()` が常に `load_all()` を呼ぶ&quot;">​</a></h3><ul><li>関連コード: <code>src/nanasqlite/core.py:825-834</code></li><li>影響: <ul><li>大規模 DB では全件メモリ展開コストが高い</li><li>少量だけ見たいケースでも全件ロードになる</li></ul></li></ul><h4 id="推奨対応-3" tabindex="-1">推奨対応 <a class="header-anchor" href="#推奨対応-3" aria-label="Permalink to &quot;推奨対応&quot;">​</a></h4><ul><li><strong>後方互換性最優先:</strong> 既存 <code>values()</code> / <code>items()</code> はそのままにする</li><li><strong>追加 API で改善:</strong> <code>iter_values()</code> / <code>iter_items()</code> のようなストリーミング API を追加する</li></ul><h3 id="_2-batch-get-のキャッシュ確認は微小ながら改善余地あり" tabindex="-1">2. <code>batch_get()</code> のキャッシュ確認は微小ながら改善余地あり <a class="header-anchor" href="#_2-batch-get-のキャッシュ確認は微小ながら改善余地あり" aria-label="Permalink to &quot;2. `batch_get()` のキャッシュ確認は微小ながら改善余地あり&quot;">​</a></h3><ul><li>関連コード: <code>src/nanasqlite/core.py:884-929</code></li><li>現状: <ul><li><code>self._cache.is_cached(key)</code> をキーごとに呼んでいる</li></ul></li><li>推奨対応: <ul><li><code>CacheType.UNBOUNDED</code> では内部集合に直接当てる軽量分岐を入れる</li></ul></li><li>期待効果: <ul><li>大量キー取得時の Python レベルのオーバーヘッド削減</li></ul></li></ul><h3 id="_3-apply-optimizations-の-pragma-はまとめ実行できる" tabindex="-1">3. <code>_apply_optimizations()</code> の PRAGMA はまとめ実行できる <a class="header-anchor" href="#_3-apply-optimizations-の-pragma-はまとめ実行できる" aria-label="Permalink to &quot;3. `_apply_optimizations()` の PRAGMA はまとめ実行できる&quot;">​</a></h3><ul><li>関連コード: <code>src/nanasqlite/core.py:309-338</code></li><li>推奨対応: <ul><li>複数の <code>cursor.execute(...)</code> をまとめて実行する</li></ul></li><li>注意: <ul><li>効果は小さいため、まずは測定してから入れる</li></ul></li></ul><h3 id="_4-いちばん効果が大きいのは既存機能の活用" tabindex="-1">4. いちばん効果が大きいのは既存機能の活用 <a class="header-anchor" href="#_4-いちばん効果が大きいのは既存機能の活用" aria-label="Permalink to &quot;4. いちばん効果が大きいのは既存機能の活用&quot;">​</a></h3><ul><li><code>pip install &quot;nanasqlite[speed]&quot;</code> を使う（<code>pyproject.toml:44-75</code>）</li><li>書き込みは <code>batch_update()</code> を優先する（<code>docs/ja/guide/best_practices.md:46-68</code>）</li><li>小さな DB は <code>bulk_load=True</code>、大きな DB はデフォルトの遅延ロードを使い分ける（<code>docs/ja/guide/best_practices.md:16-45</code>）</li><li>既存ベンチマークは <code>tests/test_benchmark.py</code> に揃っている</li></ul><h2 id="優先順位つき推奨対応" tabindex="-1">優先順位つき推奨対応 <a class="header-anchor" href="#優先順位つき推奨対応" aria-label="Permalink to &quot;優先順位つき推奨対応&quot;">​</a></h2><h3 id="優先度-p0-今すぐやるべき-非破壊" tabindex="-1">優先度 P0: 今すぐやるべき（非破壊） <a class="header-anchor" href="#優先度-p0-今すぐやるべき-非破壊" aria-label="Permalink to &quot;優先度 P0: 今すぐやるべき（非破壊）&quot;">​</a></h3><ol><li>現行の識別子サニタイズ実装を維持する</li><li><code>backup()</code> / <code>restore()</code> に未検証パスを渡さないことを運用ガイドに含める</li><li>高負荷 async 利用者向けに <code>max_workers</code> の調整指針を文書化する</li></ol><h3 id="優先度-p1-小さく安全に改善できる項目" tabindex="-1">優先度 P1: 小さく安全に改善できる項目 <a class="header-anchor" href="#優先度-p1-小さく安全に改善できる項目" aria-label="Permalink to &quot;優先度 P1: 小さく安全に改善できる項目&quot;">​</a></h3><ol><li><code>iter_values()</code> / <code>iter_items()</code> のような追加 API</li><li><code>batch_get()</code> の軽微なマイクロ最適化</li><li>PRAGMA のまとめ実行</li></ol><h3 id="優先度-p2-互換性設計を伴うため、慎重に進める項目" tabindex="-1">優先度 P2: 互換性設計を伴うため、慎重に進める項目 <a class="header-anchor" href="#優先度-p2-互換性設計を伴うため、慎重に進める項目" aria-label="Permalink to &quot;優先度 P2: 互換性設計を伴うため、慎重に進める項目&quot;">​</a></h3><ol><li><code>backup()</code> / <code>restore()</code> の opt-in パス制約</li><li>async キュー上限の opt-in 制御</li><li>AAD 付きの新しい暗号化フォーマット</li></ol><h2 id="参考資料" tabindex="-1">参考資料 <a class="header-anchor" href="#参考資料" aria-label="Permalink to &quot;参考資料&quot;">​</a></h2><ul><li>セキュリティ回帰テスト: <code>tests/test_security.py</code></li><li>ベンチマーク: <code>tests/test_benchmark.py</code></li><li>既知の修正済み問題: <code>SECURITY.md</code></li><li>PoC: <ul><li><code>etc/poc/poc_sqli.py</code></li><li><code>etc/poc/poc_none.py</code></li></ul></li></ul>',65)])])}const b=a(t,[["render",c]]);export{p as __pageData,b as default};
